# Edge-case tests for query normalization and escaping
EDGE_CASE_TESTS = {
    'Trailing dash': (
        'Horror-',
        'Horror\\-',
    ),
    'Multiple trailing dashes': (
        'test--',
        'test\\-\\-',
    ),
    'Dashes in middle': (
        'test-query',
        'test\\-query',
    ),
    'Trailing AND operator': (
        'test AND',
        'test and',
    ),
    'Trailing OR operator': (
        'test OR',
        'test or',
    ),
    'NOT operator at start': (
        'NOT test',
        'NOT test',
    ),
    'Quoted phrase with dash': (
        '"horror-movies"',
        '"horror\\-movies"',
    ),
    'Asterisk wildcard': (
        'test*',
        'test\\*',
    ),
    'Ampersand operator': (
        'foo&bar',
        'foo\\&bar',
    ),
    'Pipe operator': (
        'a||b',
        'a\\|\\|b',
    ),
    'Plus operator': (
        'foo+bar',
        'foo\\+bar',
    ),
    'Mixed special characters': (
        'test-query*&|+',
        'test\\-query\\*\\&\\|\\+',
    ),
}


